function App() {
  const { data, send } = useNodeRed();
  const s = data || { temp: 0, humidity: 0, pressure: 0 };

  return (
    <div className="min-h-screen bg-zinc-950 p-8 max-w-3xl mx-auto">
      <h1 className="text-2xl font-light text-cyan-400 mb-6">Sensor Portal</h1>
      <div className="flex gap-6 flex-wrap">
        <Gauge value={s.temp} min={-10} max={50} label="Temperature" unit="°C" />
        <Gauge value={s.humidity} min={0} max={100} label="Humidity" unit="%" />
        <Gauge value={s.pressure} min={950} max={1050} label="Pressure" unit="hPa" />
      </div>
      <div className="mt-6 flex gap-3 items-center">
        <button
          className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition-colors"
          onClick={() => send({ action: 'refresh' })}
        >Refresh</button>
        {s.ts && <span className="text-zinc-600 text-xs">Last: {new Date(s.ts).toLocaleTimeString()}</span>}
      </div>
    </div>
  );
}
